function ed_job_creation_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('ed_job_creation');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'year' => Request::val('year', '2020-21'),
		'Name_of_the_Employee' => Request::val('Name_of_the_Employee', ''),
		'gender' => Request::val('gender', 'Male'),
		'cast_category' => Request::val('cast_category', 'SC'),
		'Type_of_Employment' => Request::val('Type_of_Employment', ''),
		'Joining_Date' => Request::dateComponents('Joining_Date', ''),
		'Designation' => Request::val('Designation', ''),
		'Organisation_Name' => Request::val('Organisation_Name', ''),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('ed_job_creation', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		ed_job_creation_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function ed_job_creation_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function ed_job_creation_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('ed_job_creation', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: ed_job_creation_before_delete
	if(function_exists('ed_job_creation_before_delete')) {
		$args = [];
		if(!ed_job_creation_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `ed_job_creation` WHERE `id`='{$selected_id}'", $eo);

	// hook: ed_job_creation_after_delete
	if(function_exists('ed_job_creation_after_delete')) {
		$args = [];
		ed_job_creation_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='ed_job_creation' AND `pkValue`='{$selected_id}'", $eo);
}

function ed_job_creation_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('ed_job_creation', $selected_id, 'edit')) return false;

	$data = [
		'year' => Request::val('year', ''),
		'Name_of_the_Employee' => Request::val('Name_of_the_Employee', ''),
		'gender' => Request::val('gender', ''),
		'cast_category' => Request::val('cast_category', ''),
		'Type_of_Employment' => Request::val('Type_of_Employment', ''),
		'Joining_Date' => Request::dateComponents('Joining_Date', ''),
		'Designation' => Request::val('Designation', ''),
		'Organisation_Name' => Request::val('Organisation_Name', ''),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
	];

	if($data['year'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Year': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['gender'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Select the Candidate\'s Gender': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('ed_job_creation', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: ed_job_creation_before_update
	if(function_exists('ed_job_creation_before_update')) {
		$args = ['old_data' => $old_data];
		if(!ed_job_creation_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'ed_job_creation',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="ed_job_creation_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('ed_job_creation', $data['selectedID'], calculated_fields()['ed_job_creation']);

	// hook: ed_job_creation_after_update
	if(function_exists('ed_job_creation_after_update')) {
		if($row = getRecord('ed_job_creation', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!ed_job_creation_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('ed_job_creation', $selected_id);
}

